import gzip
import json
import base64
import itertools
import numpy as np
from Bio.SeqUtils import MeltingTemp as Tm

#_MODEL_B64 = """"""

#new azimuth 2.0
#_MODEL_B64 = """"""

#fixed azimuth 
_MODEL_B64 = """"""

def _load_model():
    compressed = base64.b64decode(_MODEL_B64)
    data = json.loads(gzip.decompress(compressed).decode('utf-8'))
    return data

_MODEL = _load_model()
_INIT_MEAN = _MODEL['init_mean']       
_LEARNING_RATE = _MODEL['learning_rate'] 
_TREES = _MODEL['trees']           

_ALPHA1 = ['A', 'T', 'C', 'G']
_ALPHA2 = [''.join(p) for p in itertools.product(_ALPHA1, repeat=2)]
_ALPHA2_NGGX = [''.join(p) for p in itertools.product(['A', 'T', 'C', 'G'], repeat=2)]


def _nuc_pd(seq, order, alphabet):
    n_pos = len(seq) - order + 1
    feat = np.zeros(len(alphabet) * n_pos)
    for pos in range(n_pos):
        nucl = seq[pos:pos + order]
        if nucl in alphabet:
            feat[alphabet.index(nucl) + pos * len(alphabet)] = 1.0
    return feat

def _nuc_pi(seq, order, alphabet):
    feat = np.zeros(len(alphabet))
    for pos in range(len(seq) - order + 1):
        nucl = seq[pos:pos + order]
        if nucl in alphabet:
            feat[alphabet.index(nucl)] += 1.0
    return feat

def _featurize(seq_30mer, pp=-1.0, aa=-1.0):
    s = seq_30mer.upper()
    if len(s) != 30:
        raise ValueError(f"Sequence must be 30 nt, got {len(s)}: {seq_30mer}")

    gc = len(s[4:24].replace('A', '').replace('T', ''))
    nx = s[24] + s[27]

    return np.concatenate([
        _nuc_pd(s, 1, _ALPHA1),                           # [0-119]   nuc_pd_Order1
        _nuc_pi(s, 1, _ALPHA1),                           # [120-123] nuc_pi_Order1
        _nuc_pd(s, 2, _ALPHA2),                           # [124-587] nuc_pd_Order2
        _nuc_pi(s, 2, _ALPHA2),                           # [588-603] nuc_pi_Order2
        [1.0 if gc > 10 else 0.0],                        # [604] gc_above_10
        [1.0 if gc < 10 else 0.0],                        # [605] gc_below_10
        [float(gc)],                                      # [606] gc_count
        _nuc_pd(nx, 2, _ALPHA2_NGGX),                     # [607-622] NGGX
        [Tm.Tm_NN(s),                                     # [623-626] Tm
        Tm.Tm_NN(s[19:24]),
        Tm.Tm_NN(s[11:19]),
        Tm.Tm_NN(s[6:11])],
    ])

def _predict_tree(tree, features):
    node = tree[0]
    while True:
        if node['l'] == -1:
            return node['v']
        if features[node['f']] <= node['t']:
            node = tree[node['l']]
        else:
            node = tree[node['r']]

def _predict_from_features(features):
    total = _INIT_MEAN
    for tree in _TREES:
        total += _LEARNING_RATE * _predict_tree(tree, features)
    return total

def predict_doench16(seq_30mer, aa_cut=-1.0, percent_peptide=-1.0):
    features = _featurize(seq_30mer, pp=percent_peptide, aa=aa_cut)
    return _predict_from_features(features)

def predict_batch(seq_30mers, aa_cuts=None, percent_peptides=None):
    n = len(seq_30mers)
    if aa_cuts is None:
        aa_cuts = [-1.0] * n
    if percent_peptides is None:
        percent_peptides = [-1.0] * n

    preds = np.zeros(n)
    for i, seq in enumerate(seq_30mers):
        features = _featurize(seq, pp=percent_peptides[i], aa=aa_cuts[i])
        preds[i] = _predict_from_features(features)
    return preds
